const __pageData = JSON.parse('{"title":"生产环境测试：混沌与可观测性","description":"系统阐述生产环境测试的形式化分类与可观测性驱动测试理论，深入映射Feature Flag、Canary部署、混沌工程工具、Synthetic Monitoring与RUM的工程实践，探讨SRE错误预算与测试策略的协同。","frontmatter":{"title":"生产环境测试：混沌与可观测性","description":"系统阐述生产环境测试的形式化分类与可观测性驱动测试理论，深入映射Feature Flag、Canary部署、混沌工程工具、Synthetic Monitoring与RUM的工程实践，探讨SRE错误预算与测试策略的协同。","date":"2026-05-01T00:00:00.000Z","tags":["测试工程","生产测试","混沌工程","可观测性","Canary","Feature Flag","SRE","Chaos Engineering"],"category":"engineering"},"headers":[],"relativePath":"testing-engineering/15-testing-in-production.md","filePath":"testing-engineering/15-testing-in-production.md","lastUpdated":1777741461000}');
